import React from "react";

const Navbar = () => {

  const handleScroll = (sectionId) => {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <nav className="bg-crimson p-4">
      <ul className="flex space-x-6 text-white font-semibold list-none m-0 p-0">
        <li>
          <button className="cursor-pointer" onClick={() => handleScroll('home')}>
            Home
          </button>
        </li>
        <li>
          <button className="cursor-pointer" onClick={() => handleScroll('about')}>
            About
          </button>
        </li>
        <li>
          <button className="cursor-pointer" onClick={() => handleScroll('projects')}>
            Projects
          </button>
        </li>
        <li>
          <button className="cursor-pointer" onClick={() => handleScroll('contact')}>
            Contact
          </button>
        </li>
      </ul>
    </nav>
  );
};

export default Navbar;
